-- Add debate pipeline columns to predictions table
-- These columns store the bull/bear research cases and risks
-- generated by the TradingAgents-inspired debate pipeline.

ALTER TABLE predictions
  ADD COLUMN IF NOT EXISTS bull_case TEXT,
  ADD COLUMN IF NOT EXISTS bear_case TEXT,
  ADD COLUMN IF NOT EXISTS risks TEXT[] DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS debate_rounds INTEGER DEFAULT 0;

COMMENT ON COLUMN predictions.bull_case IS 'Bull researcher argument from debate pipeline';
COMMENT ON COLUMN predictions.bear_case IS 'Bear researcher argument from debate pipeline';
COMMENT ON COLUMN predictions.risks IS 'Key risks identified during debate synthesis';
COMMENT ON COLUMN predictions.debate_rounds IS '0 = quick single-pass, 1+ = full bull/bear debate';
